import streamlit as st

st.title("Calculadora IMC 📱")
st.subheader("Feito com o streamlit")

altura = st.number_input("Digite a sua altura", min_value=0.0)
peso = st.number_input("Digite o seu peso", min_value=0.0)

if st.button("Calcular"):
    imc = peso / altura ** 2
    st.success(f"Seu IMC é {imc:.2f}")

    if imc < 18.5:
        st.image("https://i.pinimg.com/564x/fe/64/de/fe64de39442ed7d37096469a04fb56d5.jpg", width=200)
        st.error("Abaixo do peso 💀💀")
    elif imc < 24.9:
        st.image("https://i0.wp.com/www.portaleducadora.com/wp-content/uploads/2019/01/f5dc28002dddaf29ccc038017ed29637.jpg?w=700&h=360&zc=3", width=200)
        st.success("Tá tudo certin 👍🏽")
    elif imc < 29.9:
        st.image("data:image/jpeg;base64,", width=200)
        st.warning("🍪TIRA ESSES DOCES🍪")
    elif imc < 34.9:
        st.image("data:image/jpeg;base64,", width=200)
        st.error("Quase um planeta")
    elif imc < 39.9:
        st.image("data:image/jpeg;base64,", width=200)
        st.error("Bombastic")
    else:
        st.image("https://isinaliza.vtexassets.com/arquivos/ids/198734-800-auto?v=636989952327500000&width=800&height=auto&aspect=true", width=200)
        st.error("N aguentei")